solution_code:
#include <iostream>

int main() {
    const int secs_per_minute = 60;
    const int secs_per_hour = secs_per_minute * 60;
    const int secs_per_day = secs_per_hour * 24;

    std::cout << "Seconds per minute: " << secs_per_minute << "\n";
    std::cout << "Seconds per hour: " << secs_per_hour << "\n";
    std::cout << "Seconds per day: " << secs_per_day << "\n";
    return 0;
}

