solution_code:
#include <iostream>
#include <iomanip>

double circleArea(int radius) {
    const double pi = 3.14159;
    return pi * radius * radius;
}

int main() {
    int r;
    std::cin >> r;
    std::cout << "Area: " << std::fixed << std::setprecision(2) << circleArea(r) << "\n";
    return 0;
}
